final:
module RefModule(
    input clk,
    input reset,
    input serial_in,
    output [3:0] parallel_out
);reg [3:0] shift_reg;

always @(posedge clk) begin
    if (reset) begin
        shift_reg <= 4'b0;
    end else begin
        shift_reg <= {shift_reg[2:0], serial_in};
    end
end

wire __parallel_out_tmp = shift_reg;
assign parallel_out = __parallel_out_tmp;

endmodule
